#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> subsets(vector<int>& nums) {
        int n = nums.size();
        vector<vector<int>> output;
        for (int i = 0; i < (1 << n); i++) {
            vector<int> subset;
            for (int j = 0; j < n; j++) {
                if (i & (1 << j)) {
                    subset.push_back(nums[j]);
                }
            }
            output.push_back(subset);
        }
        return output;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int _;
    if (!(cin >> _)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    vector<vector<int>> ans = sol.subsets(nums);
    cout << ans.size() << endl;
    for (int i = 0; i < ans.size(); i++) {
        cout << '[';
        for (int j = 0; j < ans[i].size(); j++) {
            cout << ans[i][j];
            if (j != ans[i].size() - 1) cout << ',';
        }
        cout << ']' << endl;
    }
    return 0;
}
